$(document).ready(function() {
    $(window).on("load scroll", function() {
        $(".product_image").each(function() {
            var t, e;
            if (t = this, (e = t.getBoundingClientRect()).top >= 0 && e.left >= 0 && e.bottom <= (window.innerHeight || document.documentElement.clientHeight) && e.right <= (window.innerWidth || document.documentElement.clientWidth) && $(this).is(":not([style])")) {
                var a = $(this).attr("data-style");
                $(this).attr("style", a)
            }
        })
    }), $("[name=product_jump]").change(function() {
        var t = $(this).val();
        window.location.href = t
    }), $("[data-modal]").on("click", function() {
        var t = $(this).attr("data-modal");
        return $(t).iziModal({
            title: "",
            theme: "dark",
            headerColor: "",
            width: 600,
            padding: 20,
            fullscreen: !1,
            closeButton: !0,
            closeOnEscape: !0,
            overlayClose: !0,
            onOpening: function() {
                $(t).show()
            },
            onClosed: function() {
                $(t).hide()
            }
        }), $(t).iziModal("open"), !1
    }), $("[data-menu]").on("click", function() {
        var t = $(this).attr("data-menu");
        if ($(t).is("[data-extra-classes]")) {
            var e = $(t).attr("data-extra-classes"),
                a = e.split(" ")[0];
            $(t).hasClass(a) || ($(t).addClass(e), $(t).removeAttr("data-extra-classes"))
        }
        if ($(t).is("[data-remove-class]")) {
            var o = $(t).attr("data-remove-class");
            $(t).removeClass(o), $(t).removeAttr("data-remove-class")
        }
        if ($(t).hasClass("none") ? ($(t).removeClass("none"), $(".dropdown_menu").not(t).addClass("none")) : $(t).addClass("none"), $(t).hasClass("dropdown_menu")) {
            var n = $(this).offset(),
                s = $(this).outerHeight();
            $(t).css({
                top: n.top + s,
                left: n.left
            })
        }
        return !1
    }), $(".payment_method input").click(function() {
        $(".payment_method").removeClass("button_outlined"), $(this).parents(".payment_method").addClass("button_outlined")
    }), $('input[name="product"]').on("keyup", function() {
        var t = $(this).val().toLowerCase(),
            e = $('select[name="categories"]').val();
        $(".product").each(function() {
            var a = $(this).find(".product_title").text().toLowerCase();
            $(this).data("category-id") != e && 0 != e ? $(this).hide() : a.includes(t) ? $(this).show() : $(this).hide()
        })
    }), $('select[name="categories"]').on("change", function() {
        var t = $(this).val();
        0 == t ? $(".product").show() : $(".product").each(function() {
            $(this).data("category-id") == t ? $(this).show() : $(this).hide()
        })
    })
});